use crate::decoders::{Crack, CrackResult, Decoder};use crate::checkers::CheckerTypes;use std::collections::HashMap;use std::marker::PhantomData;pub struct BrailleDecoder;fn build_braille_map() -> HashMap<&'static str, &'static str> {    let mut m = HashMap::new();    m.insert("\u{2801}", "a"); m.insert("\u{2803}", "b"); m.insert("\u{2809}", "c");    m.insert("\u{2819}", "d"); m.insert("\u{2811}", "e"); m.insert("\u{280b}", "f");    m.insert("\u{281b}", "g"); m.insert("\u{2813}", "h"); m.insert("\u{280a}", "i");    m.insert("\u{281a}", "j"); m.insert("\u{2805}", "k"); m.insert("\u{2807}", "l");    m.insert("\u{280d}", "m"); m.insert("\u{281d}", "n"); m.insert("\u{2815}", "o");    m.insert("\u{280f}", "p"); m.insert("\u{281f}", "q"); m.insert("\u{2817}", "r");    m.insert("\u{280e}", "s"); m.insert("\u{281e}", "t"); m.insert("\u{2825}", "u");    m.insert("\u{2827}", "v"); m.insert("\u{283a}", "w"); m.insert("\u{282d}", "x");    m.insert("\u{283d}", "y"); m.insert("\u{2835}", "z");    m.insert("\u{2800}", " ");    m}impl Crack for Decoder<BrailleDecoder> {    fn crack(&self, text: &str, checker: &CheckerTypes) -> CrackResult {        let mut result = CrackResult::new(self.get_name(), self.get_description(), self.get_link());        result.encrypted_text = text.to_string();        let braille_map = build_braille_map();        let mut decoded = String::new();        let mut found_braille = false;        for ch in text.chars() {            let s: String = ch.to_string();            if let Some(letter) = braille_map.get(s.as_str()) {                decoded.push_str(letter);                found_braille = true;            } else if ch == ' ' {                decoded.push(' ');            }        }        if found_braille && !decoded.is_empty() {            let check_result = checker.check_text(&decoded);            if check_result.is_identified {                result.success = true;                result.unencrypted_text = Some(vec![decoded]);                result.checker_name = check_result.checker_name;            }        }        result    }    fn get_name(&self) -> &'static str { "Braille" }    fn get_popularity(&self) -> f32 { 0.3 }    fn get_tags(&self) -> &'static [&'static str] { &["braille", "decoder", "unicode"] }    fn get_description(&self) -> &'static str { "Braille is a tactile writing system using raised dots, represented in Unicode as Braille Patterns." }    fn get_link(&self) -> &'static str { "https://en.wikipedia.org/wiki/Braille" }}impl Decoder<BrailleDecoder> {    pub fn new() -> Self {        Decoder {            name: "Braille",            description: "Braille is a tactile writing system using raised dots.",            link: "https://en.wikipedia.org/wiki/Braille",            tags: vec!["braille", "decoder", "unicode"],            popularity: 0.3,            phantom: PhantomData,        }    }}



